import{_ as s,o as a,c as n,a4 as e}from"./chunks/framework._in6GHBg.js";const h=JSON.parse('{"title":"曲线运动详解","description":"","frontmatter":{},"headers":[],"relativePath":"physics/curved.md","filePath":"physics/curved.md"}'),l={name:"physics/curved.md"};function p(i,t,r,d,o,c){return a(),n("div",null,[...t[0]||(t[0]=[e(`<h1 id="曲线运动详解" tabindex="-1">曲线运动详解 <a class="header-anchor" href="#曲线运动详解" aria-label="Permalink to &quot;曲线运动详解&quot;">​</a></h1><p><strong>类别四：曲线运动与天体运动</strong><br><strong>学习时机</strong>：高一下学期 2-4月<br><strong>核心能力</strong>：二维运动分析、向心力分析、万有引力应用</p><hr><h2 id="类别概述" tabindex="-1">类别概述 <a class="header-anchor" href="#类别概述" aria-label="Permalink to &quot;类别概述&quot;">​</a></h2><p>曲线运动是高中物理从直线到曲线的关键转折，核心思想是<strong>化曲为直</strong>——通过运动的合成与分解，将复杂的曲线运动转化为熟悉的直线运动处理。</p><p><strong>三个模型的递进关系</strong>：</p><ul><li><strong>模型13 圆周运动</strong>：曲线运动的基础，掌握向心力来源分析</li><li><strong>模型14 圆锥摆</strong>：圆周运动的典型应用，强调几何关系</li><li><strong>模型15 天体运动</strong>：万有引力提供向心力，是圆周运动的宇宙尺度推广</li></ul><p><strong>核心思想</strong>：</p><ul><li>曲线运动必有向心力（改变速度方向）</li><li>向心力由实际力（重力、弹力、摩擦力、万有引力）提供</li><li>天体运动中，万有引力=向心力=重力（近似）</li></ul><hr><h2 id="模型13-圆周运动" tabindex="-1">模型13：圆周运动 <a class="header-anchor" href="#模型13-圆周运动" aria-label="Permalink to &quot;模型13：圆周运动&quot;">​</a></h2><h3 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h3><p><strong>圆周运动的描述</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">物理量</th><th style="text-align:left;">公式</th><th style="text-align:left;">关系</th></tr></thead><tbody><tr><td style="text-align:center;">线速度</td><td style="text-align:left;">v = 2πr/T = ωr</td><td style="text-align:left;">描述运动快慢</td></tr><tr><td style="text-align:center;">角速度</td><td style="text-align:left;">ω = 2π/T = v/r</td><td style="text-align:left;">描述转动快慢</td></tr><tr><td style="text-align:center;">周期</td><td style="text-align:left;">T = 2πr/v = 2π/ω</td><td style="text-align:left;">转动一圈的时间</td></tr><tr><td style="text-align:center;">频率</td><td style="text-align:left;">f = 1/T</td><td style="text-align:left;">每秒转动的圈数</td></tr></tbody></table><p><strong>向心力公式</strong>（核心）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>F向 = mv²/r = mω²r = m(2π/T)²r = m(2πf)²r</span></span></code></pre></div><p><strong>向心加速度</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>a向 = v²/r = ω²r</span></span></code></pre></div><h3 id="关键方法-向心力来源分析" tabindex="-1">关键方法：向心力来源分析 <a class="header-anchor" href="#关键方法-向心力来源分析" aria-label="Permalink to &quot;关键方法：向心力来源分析&quot;">​</a></h3><p><strong>步骤</strong>：</p><ol><li><strong>确定圆周平面</strong>（水平/竖直/倾斜）</li><li><strong>受力分析</strong>（重力、弹力、摩擦力）</li><li><strong>指向圆心的合力 = 向心力</strong></li></ol><p><strong>常见情景</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">情景</th><th style="text-align:left;">向心力来源</th><th style="text-align:left;">注意点</th></tr></thead><tbody><tr><td style="text-align:left;">水平转盘上的物块</td><td style="text-align:left;">静摩擦力</td><td style="text-align:left;">f_max = μN，有最大角速度限制</td></tr><tr><td style="text-align:left;">绳系小球水平面内转动</td><td style="text-align:left;">绳拉力的水平分力</td><td style="text-align:left;">与圆锥摆区分</td></tr><tr><td style="text-align:left;">汽车转弯</td><td style="text-align:left;">静摩擦力（平地）或重力与支持力的合力（倾斜路面）</td><td style="text-align:left;">有最大安全速度</td></tr><tr><td style="text-align:left;">过山车最高点</td><td style="text-align:left;">重力+支持力（向下）</td><td style="text-align:left;">临界：N=0，仅重力提供向心力</td></tr></tbody></table><h3 id="竖直平面内圆周运动的临界问题" tabindex="-1">竖直平面内圆周运动的临界问题 <a class="header-anchor" href="#竖直平面内圆周运动的临界问题" aria-label="Permalink to &quot;竖直平面内圆周运动的临界问题&quot;">​</a></h3><p><strong>绳模型（只能拉）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最高点临界：T = 0，仅重力提供向心力</span></span>
<span class="line"><span>mg = mv²/r → v临界 = √(gr)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>通过条件：v ≥ √(gr)</span></span></code></pre></div><p><strong>杆模型（可拉可推）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最高点临界：v = 0（杆可以支撑）</span></span>
<span class="line"><span>当 0 &lt; v &lt; √(gr)：杆向上推</span></span>
<span class="line"><span>当 v = √(gr)：杆无力</span></span>
<span class="line"><span>当 v &gt; √(gr)：杆向下拉</span></span></code></pre></div><p><strong>对比记忆</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">模型</th><th style="text-align:center;">最高点最小速度</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:center;">绳/环/外轨道</td><td style="text-align:center;">√(gr)</td><td style="text-align:left;">只能单向约束</td></tr><tr><td style="text-align:center;">杆/管/双轨道</td><td style="text-align:center;">0</td><td style="text-align:left;">可双向约束</td></tr></tbody></table><h3 id="典型例题" tabindex="-1">典型例题 <a class="header-anchor" href="#典型例题" aria-label="Permalink to &quot;典型例题&quot;">​</a></h3><p><strong>【例题1】水平面内圆周运动</strong></p><p>一根长为L的轻绳，一端固定，另一端系一质量为m的小球，在水平面内做匀速圆周运动，绳与竖直方向夹角为θ。</p><p>求：线速度v和周期T</p><p><strong>解析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>受力分析：重力mg向下，绳拉力T沿绳向上</span></span>
<span class="line"><span></span></span>
<span class="line"><span>竖直方向平衡：Tcosθ = mg  →  T = mg/cosθ</span></span>
<span class="line"><span></span></span>
<span class="line"><span>水平方向（指向圆心）：Tsinθ = mv²/r</span></span>
<span class="line"><span>其中 r = Lsinθ（圆周半径）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>代入：</span></span>
<span class="line"><span>(mg/cosθ)·sinθ = mv²/(Lsinθ)</span></span>
<span class="line"><span>g·tanθ = v²/(Lsinθ)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解得：</span></span>
<span class="line"><span>v = √(gLsinθ·tanθ) = √(gLsin²θ/cosθ)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>周期：</span></span>
<span class="line"><span>T = 2πr/v = 2πLsinθ / √(gLsin²θ/cosθ) = 2π√(Lcosθ/g)</span></span></code></pre></div><p><strong>【例题2】竖直圆周运动临界</strong></p><p>一质量为m的小球用长为L的轻绳系着，在竖直平面内做圆周运动。</p><p>(1) 求小球能通过最高点的最小速度 (2) 若小球在最高点速度为2√(gL)，求绳的拉力</p><p><strong>解析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(1) 最高点临界：仅重力提供向心力</span></span>
<span class="line"><span>    mg = mv²/L → v_min = √(gL)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(2) v = 2√(gL) &gt; √(gL)，绳向下拉</span></span>
<span class="line"><span>    牛顿第二定律（向下为正）：</span></span>
<span class="line"><span>    mg + T = mv²/L = m·4gL/L = 4mg</span></span>
<span class="line"><span>    T = 3mg</span></span></code></pre></div><h3 id="faq小节" tabindex="-1">FAQ小节 <a class="header-anchor" href="#faq小节" aria-label="Permalink to &quot;FAQ小节&quot;">​</a></h3><p><strong>Q1：向心力是实际存在的力吗？</strong></p><blockquote><p>不是。向心力是效果力，由实际力（重力、弹力、摩擦力）的合力或分力提供。分析时不能说&quot;物体受向心力&quot;，而要说&quot;某某力提供向心力&quot;。</p></blockquote><p><strong>Q2：为什么最高点临界速度是√(gr)？</strong></p><blockquote><p>当速度小于√(gr)时，需要的向心力mv²/r &lt; mg，重力&quot;过剩&quot;，物体会掉下来。绳模型中绳子不能推，所以必须满足v ≥ √(gr)。</p></blockquote><p><strong>Q3：角速度和线速度什么时候用哪个公式？</strong></p><blockquote><ul><li>同轴转动（如转盘上各点）：角速度ω相同，用v = ωr比较线速度</li><li>皮带/齿轮传动：线速度v相同，用ω = v/r比较角速度</li></ul></blockquote><hr><h2 id="模型14-圆锥摆" tabindex="-1">模型14：圆锥摆 <a class="header-anchor" href="#模型14-圆锥摆" aria-label="Permalink to &quot;模型14：圆锥摆&quot;">​</a></h2><h3 id="核心模型" tabindex="-1">核心模型 <a class="header-anchor" href="#核心模型" aria-label="Permalink to &quot;核心模型&quot;">​</a></h3><p><strong>结构</strong>：小球在水平面内做匀速圆周运动，绳与竖直方向成θ角，形成圆锥面。</p><p><strong>受力</strong>：重力mg向下，绳拉力T沿绳向上</p><p><strong>关键方程</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>竖直平衡：Tcosθ = mg</span></span>
<span class="line"><span>水平向心力：Tsinθ = mω²r</span></span>
<span class="line"><span></span></span>
<span class="line"><span>其中 r = Lsinθ（圆周半径）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>联立得：</span></span>
<span class="line"><span>tanθ = ω²r/g = ω²Lsinθ/g</span></span>
<span class="line"><span>ω² = g/(Lcosθ)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>周期：</span></span>
<span class="line"><span>T = 2π/ω = 2π√(Lcosθ/g)</span></span></code></pre></div><p><strong>重要结论</strong>：</p><ul><li>周期只与L和θ有关，与质量无关</li><li>θ越大，cosθ越小，周期越小，角速度越大</li><li>同一高度的圆锥摆周期相同（与绳长无关）</li></ul><h3 id="与单摆的区别" tabindex="-1">与单摆的区别 <a class="header-anchor" href="#与单摆的区别" aria-label="Permalink to &quot;与单摆的区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">对比</th><th style="text-align:center;">圆锥摆</th><th style="text-align:center;">单摆</th></tr></thead><tbody><tr><td style="text-align:center;">运动</td><td style="text-align:center;">水平面匀速圆周</td><td style="text-align:center;">竖直平面变速摆动</td></tr><tr><td style="text-align:center;">周期公式</td><td style="text-align:center;">T = 2π√(Lcosθ/g)</td><td style="text-align:center;">T = 2π√(L/g)</td></tr><tr><td style="text-align:center;">速度大小</td><td style="text-align:center;">恒定</td><td style="text-align:center;">变化（最低点最大）</td></tr><tr><td style="text-align:center;">加速度</td><td style="text-align:center;">向心加速度（水平）</td><td style="text-align:center;">切向+向心加速度</td></tr></tbody></table><hr><h2 id="模型15-天体运动" tabindex="-1">模型15：天体运动 <a class="header-anchor" href="#模型15-天体运动" aria-label="Permalink to &quot;模型15：天体运动&quot;">​</a></h2><h3 id="核心模型-1" tabindex="-1">核心模型 <a class="header-anchor" href="#核心模型-1" aria-label="Permalink to &quot;核心模型&quot;">​</a></h3><p><strong>基本假设</strong>：天体运动近似为匀速圆周运动，万有引力提供向心力</p><p><strong>万有引力定律</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>F = GMm/r²</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G = 6.67×10⁻¹¹ N·m²/kg²（引力常量）</span></span></code></pre></div><p><strong>核心方程</strong>：万有引力 = 向心力</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GMm/r² = mv²/r = mω²r = m(2π/T)²r</span></span></code></pre></div><h3 id="常用结论-需熟记" tabindex="-1">常用结论（需熟记） <a class="header-anchor" href="#常用结论-需熟记" aria-label="Permalink to &quot;常用结论（需熟记）&quot;">​</a></h3><p><strong>线速度</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>v = √(GM/r)</span></span></code></pre></div><blockquote><p>轨道半径越大，线速度越小（高轨低速）</p></blockquote><p><strong>角速度</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ω = √(GM/r³)</span></span></code></pre></div><blockquote><p>轨道半径越大，角速度越小（高轨慢角速）</p></blockquote><p><strong>周期</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T = 2π√(r³/GM)</span></span></code></pre></div><blockquote><p>轨道半径越大，周期越大（高轨大周期）——开普勒第三定律</p></blockquote><p><strong>向心加速度</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>a = GM/r²</span></span></code></pre></div><blockquote><p>轨道半径越大，加速度越小</p></blockquote><p><strong>口诀</strong>：<strong>高轨低速大周期</strong></p><h3 id="黄金代换" tabindex="-1">黄金代换 <a class="header-anchor" href="#黄金代换" aria-label="Permalink to &quot;黄金代换&quot;">​</a></h3><p><strong>适用条件</strong>：星球表面或近地轨道（忽略自转）</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>万有引力 ≈ 重力</span></span>
<span class="line"><span>GMm/R² = mg</span></span>
<span class="line"><span></span></span>
<span class="line"><span>GM = gR²（黄金代换）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>用于：不知道M，但知道g和R时</span></span></code></pre></div><h3 id="典型情景" tabindex="-1">典型情景 <a class="header-anchor" href="#典型情景" aria-label="Permalink to &quot;典型情景&quot;">​</a></h3><p><strong>情景1：比较不同卫星参数</strong></p><p>已知：卫星A轨道半径r₁，卫星B轨道半径r₂，且r₁ &lt; r₂</p><p>比较：v₁ vs v₂，ω₁ vs ω₂，T₁ vs T₂，a₁ vs a₂</p><p><strong>解析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>由 v = √(GM/r)：r小则v大 → v₁ &gt; v₂</span></span>
<span class="line"><span>由 ω = √(GM/r³)：r小则ω大 → ω₁ &gt; ω₂</span></span>
<span class="line"><span>由 T = 2π√(r³/GM)：r小则T小 → T₁ &lt; T₂</span></span>
<span class="line"><span>由 a = GM/r²：r小则a大 → a₁ &gt; a₂</span></span></code></pre></div><p><strong>情景2：求星球质量或密度</strong></p><p>已知：卫星绕星球做匀速圆周运动，轨道半径r，周期T</p><p>求：星球质量M</p><p><strong>解析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>万有引力 = 向心力</span></span>
<span class="line"><span>GMm/r² = m(2π/T)²r</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解得：</span></span>
<span class="line"><span>M = 4π²r³/GT²</span></span>
<span class="line"><span></span></span>
<span class="line"><span>若已知星球半径R，求密度：</span></span>
<span class="line"><span>ρ = M/V = M/(4/3·πR³) = 3πr³/GT²R³</span></span>
<span class="line"><span></span></span>
<span class="line"><span>近地卫星(r≈R)：</span></span>
<span class="line"><span>ρ = 3π/GT²（只需测周期即可求密度）</span></span></code></pre></div><p><strong>情景3：第一宇宙速度</strong></p><p>定义：卫星在星球表面附近绕星球做匀速圆周运动的速度</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>万有引力 = 向心力</span></span>
<span class="line"><span>GMm/R² = mv²/R</span></span>
<span class="line"><span></span></span>
<span class="line"><span>v₁ = √(GM/R) = √(gR)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>地球：v₁ ≈ 7.9 km/s</span></span></code></pre></div><p><strong>三种宇宙速度</strong>（地球）：</p><table tabindex="0"><thead><tr><th style="text-align:center;">宇宙速度</th><th style="text-align:center;">数值</th><th style="text-align:left;">意义</th></tr></thead><tbody><tr><td style="text-align:center;">第一</td><td style="text-align:center;">7.9 km/s</td><td style="text-align:left;">最小发射速度，最大环绕速度</td></tr><tr><td style="text-align:center;">第二</td><td style="text-align:center;">11.2 km/s</td><td style="text-align:left;">脱离地球引力束缚</td></tr><tr><td style="text-align:center;">第三</td><td style="text-align:center;">16.7 km/s</td><td style="text-align:left;">脱离太阳系</td></tr></tbody></table><h3 id="卫星变轨问题" tabindex="-1">卫星变轨问题 <a class="header-anchor" href="#卫星变轨问题" aria-label="Permalink to &quot;卫星变轨问题&quot;">​</a></h3><p><strong>基本规律</strong>：</p><ul><li><strong>点火加速</strong> → 做离心运动 → 轨道升高 → 机械能增加</li><li><strong>点火减速</strong> → 做向心运动 → 轨道降低 → 机械能减少</li></ul><p><strong>高轨 vs 低轨对比</strong>（同一卫星）：</p><table tabindex="0"><thead><tr><th style="text-align:center;">参数</th><th style="text-align:center;">高轨</th><th style="text-align:center;">低轨</th><th style="text-align:center;">变化</th></tr></thead><tbody><tr><td style="text-align:center;">线速度v</td><td style="text-align:center;">小</td><td style="text-align:center;">大</td><td style="text-align:center;">减速升轨</td></tr><tr><td style="text-align:center;">角速度ω</td><td style="text-align:center;">小</td><td style="text-align:center;">大</td><td style="text-align:center;">减速升轨</td></tr><tr><td style="text-align:center;">周期T</td><td style="text-align:center;">大</td><td style="text-align:center;">小</td><td style="text-align:center;">升轨周期变大</td></tr><tr><td style="text-align:center;">机械能E</td><td style="text-align:center;">大</td><td style="text-align:center;">小</td><td style="text-align:center;">升轨需点火加速</td></tr><tr><td style="text-align:center;">动能Ek</td><td style="text-align:center;">小</td><td style="text-align:center;">大</td><td style="text-align:center;">速度减小</td></tr><tr><td style="text-align:center;">势能Ep</td><td style="text-align:center;">大</td><td style="text-align:center;">小</td><td style="text-align:center;">高度增加</td></tr></tbody></table><p><strong>注意</strong>：升轨后虽然速度减小，但动能减小、势能增加更多，总机械能增加（发动机做功）。</p><h3 id="典型例题-1" tabindex="-1">典型例题 <a class="header-anchor" href="#典型例题-1" aria-label="Permalink to &quot;典型例题&quot;">​</a></h3><p><strong>【例题】同步卫星</strong></p><p>地球同步卫星距地面高度h，地球半径R，地球表面重力加速度g。</p><p>求：同步卫星的线速度v和周期T</p><p><strong>解析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>同步卫星特点：周期T = 24h = 86400s（与地球自转周期相同）</span></span>
<span class="line"><span>轨道半径：r = R + h</span></span>
<span class="line"><span></span></span>
<span class="line"><span>由万有引力 = 向心力：</span></span>
<span class="line"><span>GMm/r² = m(2π/T)²r</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解得：</span></span>
<span class="line"><span>r³ = GMT²/4π²</span></span>
<span class="line"><span></span></span>
<span class="line"><span>由黄金代换 GM = gR²：</span></span>
<span class="line"><span>r³ = gR²T²/4π²</span></span>
<span class="line"><span></span></span>
<span class="line"><span>线速度：</span></span>
<span class="line"><span>v = 2πr/T = 2π(R+h)/T</span></span></code></pre></div><h3 id="faq小节-1" tabindex="-1">FAQ小节 <a class="header-anchor" href="#faq小节-1" aria-label="Permalink to &quot;FAQ小节&quot;">​</a></h3><p><strong>Q1：卫星的向心加速度与重力加速度有什么关系？</strong></p><blockquote><p>在轨道处：a向 = GM/r²（万有引力产生的加速度） 在地面：g = GM/R² 所以 a向/g = R²/r²，轨道越高，向心加速度越小</p></blockquote><p><strong>Q2：为什么同步卫星只能定点在赤道上空？</strong></p><blockquote><p>同步卫星要与地球自转同步，其轨道圆心必须在地球自转轴上。只有赤道轨道满足这一条件，倾斜轨道或极地轨道的圆心不在地轴上，无法与地球同步。</p></blockquote><p><strong>Q3：卫星变轨时，为什么加速反而轨道升高、速度减小？</strong></p><blockquote><p>点火加速瞬间，卫星速度增大，需要的向心力mv²/r增大，但万有引力不变，不足以提供向心力，卫星做离心运动，轨道升高。 到达新高轨后，由v = √(GM/r)，r增大导致v减小，最终速度比低轨还小。</p></blockquote><hr><h2 id="类别总结" tabindex="-1">类别总结 <a class="header-anchor" href="#类别总结" aria-label="Permalink to &quot;类别总结&quot;">​</a></h2><p><strong>曲线运动三类问题对比</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">问题类型</th><th style="text-align:left;">关键分析</th><th style="text-align:left;">核心公式</th></tr></thead><tbody><tr><td style="text-align:center;">圆周运动</td><td style="text-align:left;">向心力来源</td><td style="text-align:left;">F向 = mv²/r = mω²r</td></tr><tr><td style="text-align:center;">圆锥摆</td><td style="text-align:left;">几何关系</td><td style="text-align:left;">T = 2π√(Lcosθ/g)</td></tr><tr><td style="text-align:center;">天体运动</td><td style="text-align:left;">万有引力=向心力</td><td style="text-align:left;">v = √(GM/r)，T = 2π√(r³/GM)</td></tr></tbody></table><p><strong>高频考点</strong>：</p><ol><li>竖直平面内圆周运动临界（绳/杆模型）</li><li>天体运动参数比较（高轨低速大周期）</li><li>卫星变轨问题（加速升轨，减速降轨）</li><li>第一宇宙速度计算</li></ol><p><strong>与后续知识联系</strong>：</p><ul><li>天体运动 → 万有引力势能（大学内容）</li><li>圆周运动 → 洛伦兹力作用下带电粒子圆周运动（电磁学）</li></ul>`,127)])])}const b=s(l,[["render",p]]);export{h as __pageData,b as default};
